function LiveRentalsSection({ requests }: { requests: QuoteRequestWithId[] }) {
    const today = new Date();
    
    const activeRentals = requests.filter(req => {
        const startDate = new Date(req.rentalStartDate);
        const endDate = new Date(req.rentalEndDate);
        return (req.status === 'Approved' || req.status === 'Paid') && today >= startDate && today <= endDate;
    });

    const hiredEquipment = activeRentals.reduce((acc, rental) => {
        rental.items.forEach(item => {
            if (acc[item.name]) {
                acc[item.name] += item.quantity;
            } else {
                acc[item.name] = item.quantity;
            }
        });
        return acc;
    }, {} as { [key: string]: number });
    
    return (
        <div className="grid gap-8 md:grid-cols-2 mb-8">
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2"><Users className="h-5 w-5 text-primary" />Current Renters</CardTitle>
                    <CardDescription>Customers with active rentals today.</CardDescription>
                </CardHeader>
                <CardContent>
                    {activeRentals.length > 0 ? (
                        <ul className="space-y-3">
                            {activeRentals.map(rental => (
                                <li key={rental.id} className="flex justify-between items-center p-2 rounded-lg bg-muted/50">
                                    <div>
                                        <p className="font-semibold">{rental.customerName}</p>
                                        <p className="text-sm text-muted-foreground">{new Date(rental.rentalStartDate).toLocaleDateString()} - {new Date(rental.rentalEndDate).toLocaleDateString()}</p>
                                    </div>
                                    <Badge variant={rental.status === 'Paid' ? 'default' : 'secondary'}>{rental.status === 'Paid' ? 'Paid' : 'Active'}</Badge>
                                </li>
                            ))}
                        </ul>
                    ) : ( <p className="text-sm text-muted-foreground text-center py-4">No active rentals today.</p> )}
                </CardContent>
            </Card>
             <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2"><Wrench className="h-5 w-5 text-primary" />Equipment on Hire</CardTitle>
                    <CardDescription>A live look at all equipment currently hired out.</CardDescription>
                </CardHeader>
                <CardContent>
                     {Object.keys(hiredEquipment).length > 0 ? (
                        <ul className="space-y-3">
                            {Object.entries(hiredEquipment).map(([name, quantity]) => (
                                <li key={name} className="flex justify-between items-center p-2 rounded-lg bg-muted/50">
                                    <p className="font-semibold">{name}</p>
                                    <p className="text-sm text-muted-foreground font-mono bg-background px-2 py-1 rounded-md">Qty: {quantity}</p>
                                </li>
                            ))}
                        </ul>
                    ) : ( <p className="text-sm text-muted-foreground text-center py-4">No equipment currently on hire.</p> )}
                </CardContent>
            </Card>
        </div>
    )
}

function RentalCalendar({ requests }: { requests: QuoteRequestWithId[] }) {
    const approvedRentals = requests.filter(req => req.status === 'Approved' || req.status === 'Paid');

    const rentalEvents = approvedRentals.flatMap(req => [
        { date: new Date(req.rentalStartDate), type: 'start', customer: req.customerName },
        { date: new Date(req.rentalEndDate), type: 'end', customer: req.customerName },
    ]);

    const DayContent = (props: { date: Date }) => {
        const eventsOnDay = rentalEvents.filter(event => event.date.toDateString() === props.date.toDateString());
        if (eventsOnDay.length === 0) return <span>{props.date.getDate()}</span>;
        const startEvents = eventsOnDay.filter(e => e.type === 'start');
        const endEvents = eventsOnDay.filter(e => e.type === 'end');

        return (
            <TooltipProvider>
                <Tooltip>
                    <TooltipTrigger asChild>
                        <div className="relative w-full h-full flex items-center justify-center">
                            {startEvents.length > 0 && <div className="absolute inset-0 bg-green-200 dark:bg-green-800 rounded-md z-0 opacity-75"></div>}
                            {endEvents.length > 0 && !startEvents.length && <div className="absolute inset-0 bg-red-200 dark:bg-red-800 rounded-md z-0 opacity-75"></div>}
                             <span className="relative z-10">{props.date.getDate()}</span>
                        </div>
                    </TooltipTrigger>
                    <TooltipContent>
                        <ul className="space-y-1">
                             {startEvents.map((event, i) => <li key={`start-${i}`} className="text-xs text-green-600 dark:text-green-300">Start: {event.customer}</li>)}
                             {endEvents.map((event, i) => <li key={`end-${i}`} className="text-xs text-red-600 dark:text-red-300">End: {event.customer}</li>)}
                        </ul>
                    </TooltipContent>
                </Tooltip>
            </TooltipProvider>
        );
    };

    return (
        <Card>
            <CardHeader>
                <CardTitle className="flex items-center gap-2"><CalendarIcon className="h-5 w-5 text-primary" />Rental Schedule</CardTitle>
                <CardDescription>Visual overview of rental start (green) and end (red) dates. Hover for details.</CardDescription>
            </CardHeader>
            <CardContent className="flex justify-center">
                 <Calendar numberOfMonths={2} components={{ Day: DayContent }} className="p-0" />
            </CardContent>
        </Card>
    );
}

function QuoteRequestDetails({ request, allRequests, inventory }: { request: QuoteRequestWithId; allRequests: QuoteRequestWithId[]; inventory: InventoryItem[] }) {
    const formatPrice = (price: number) => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(price);
    const { items, rentalStartDate, rentalEndDate, stakitShield } = request;
    const deliveryFee = 30;
    const stakitShieldFee = 20;

    const subtotal = useMemo(() => {
        return items.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    }, [items]);

    const { extraWeeks, extensionFee } = useMemo(() => {
        let extraWeeks = 0;
        if (rentalStartDate && rentalEndDate) {
            const start = new Date(rentalStartDate);
            const end = new Date(rentalEndDate);
            if (end > start) {
                const diffTime = end.getTime() - start.getTime();
                const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
                if (diffDays > 7) {
                    const totalWeeks = Math.ceil(diffDays / 7);
                    extraWeeks = totalWeeks - 1;
                }
            }
        }

        const fee = items.reduce((acc, item) => {
            if (item.followOnPrice) {
                return acc + (item.quantity * item.followOnPrice * extraWeeks);
            }
            return acc;
        }, 0);

        return { extraWeeks, extensionFee: fee };
    }, [rentalStartDate, rentalEndDate, items]);

    const total = subtotal + deliveryFee + extensionFee + (stakitShield ? stakitShieldFee : 0);

    const inventoryStatus = useMemo(() => {
        const requestStart = new Date(request.rentalStartDate);
        const requestEnd = new Date(request.rentalEndDate);

        const overlappingRequests = allRequests.filter(otherReq => {
            if (otherReq.id === request.id) return false;
            if (otherReq.status !== 'Approved' && otherReq.status !== 'Paid') return false;
            const otherStart = new Date(otherReq.rentalStartDate);
            const otherEnd = new Date(otherReq.rentalEndDate);
            return requestStart < otherEnd && requestEnd > otherStart;
        });

        // --- Crate Calculation ---
        const totalCrates = inventory.find(i => i.id === 'crates')?.quantity || 0;
        const neededCrates = calculateCratesForRequest(request.items);
        const reservedCrates = overlappingRequests.reduce((acc, req) => acc + calculateCratesForRequest(req.items), 0);
        const availableCrates = totalCrates - reservedCrates;
        let crateStatus: { needed: number; available: number; status: string } | null = null;
        if (neededCrates > 0) {
            let status = 'In Stock';
            if (availableCrates < neededCrates) status = 'Out of Stock';
            else if (availableCrates - neededCrates < 25) status = 'Low Stock';
            crateStatus = { needed: neededCrates, available: availableCrates, status };
        }

        // --- Individual Item Calculation ---
        const itemStatus = request.items
            .filter(item => boxHireServices.every(bh => !item.id.startsWith(bh.id)))
            .map(item => {
                const inventoryItem = inventory.find(i => i.id === item.id);
                const totalItem = inventoryItem?.quantity || 0;
                
                const reservedItem = overlappingRequests.reduce((acc, req) => {
                    const reqItem = req.items.find(i => i.id === item.id);
                    return acc + (reqItem ? reqItem.quantity : 0);
                }, 0);
                
                const availableItem = totalItem - reservedItem;
                let status = 'In Stock';
                if (availableItem < item.quantity) status = 'Out of Stock';
                else if (availableItem - item.quantity <= 2) status = 'Low Stock';
                
                return { name: item.name, needed: item.quantity, available: availableItem, status };
            });

        return { crateStatus, itemStatus };
    }, [request, allRequests, inventory]);


    return (
        <div className="p-4 bg-muted/20 dark:bg-muted/50 rounded-b-lg space-y-4">
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-2 grid md:grid-cols-2 gap-6">
                    <div className="space-y-4">
                        <div className="flex items-start gap-2"><User className="h-4 w-4 text-muted-foreground mt-1" /><div><span className="font-semibold">Customer:</span><p>{request.customerName} ({request.customerEmail})</p></div></div>
                        <div className="flex items-start gap-2"><CalendarIcon className="h-4 w-4 text-muted-foreground mt-1" /><div><span className="font-semibold">Rental Period:</span><p>{new Date(request.rentalStartDate).toLocaleDateString()} - {new Date(request.rentalEndDate).toLocaleDateString()}</p></div></div>
                        <div className="flex items-start gap-2"><Search className="h-4 w-4 text-muted-foreground mt-1" /><div><span className="font-semibold">Drop-off / Collection:</span><p>{request.dropOffAddress}</p>{request.collectionAddress && request.collectionAddress !== request.dropOffAddress && <p>{request.collectionAddress}</p>}</div></div>
                        <div className="flex items-start gap-2"><Hash className="h-4 w-4 text-muted-foreground mt-1" /><div><span className="font-semibold">Request ID:</span><p className="text-xs font-mono">{request.id}</p></div></div>
                        {request.stakitShield && <div className="flex items-start gap-2"><Shield className="h-4 w-4 text-muted-foreground mt-1" /><div><span className="font-semibold">Box Protection Plan:</span><p>Purchased</p></div></div>}
                    </div>
                    <div className="space-y-4">
                        <h4 className="font-semibold">Itemized Quote</h4>
                        <table className="w-full">
                            <thead><tr><th className="text-left py-2 font-normal text-muted-foreground">Item</th><th className="text-center py-2 font-normal text-muted-foreground">Qty</th><th className="text-right py-2 font-normal text-muted-foreground">Price</th></tr></thead>
                            <tbody>{request.items.map((item, index) => (<tr key={index} className="border-b"><td className="py-2">{item.name}</td><td className="text-center py-2">{item.quantity}</td><td className="text-right py-2">{formatPrice(item.price * item.quantity)}</td></tr>))}</tbody>
                            <tfoot>
                                <tr><td colSpan={2} className="py-2 font-semibold text-muted-foreground">Subtotal</td><td className="text-right py-2 font-semibold">{formatPrice(subtotal)}</td></tr>
                                <tr><td colSpan={2} className="py-2 text-muted-foreground">Delivery Fee</td><td className="text-right py-2">{formatPrice(deliveryFee)}</td></tr>
                                {extensionFee > 0 && (<tr><td colSpan={2} className="py-2 text-muted-foreground">Rental Extension ({extraWeeks} extra {extraWeeks > 1 ? 'weeks' : 'week'})</td><td className="text-right py-2">{formatPrice(extensionFee)}</td></tr>)}
                                {stakitShield && (<tr><td colSpan={2} className="py-2 text-muted-foreground">Box Protection Plan</td><td className="text-right py-2">{formatPrice(stakitShieldFee)}</td></tr>)}
                                <tr className="border-t-2 border-primary/20"><td colSpan={2} className="py-2 font-bold text-lg">Estimated Total</td><td className="text-right py-2 font-bold text-lg">{formatPrice(total)}</td></tr>
                            </tfoot>
                        </table>
                    </div>
                </div>
                <div className="lg:col-span-1">
                     <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2 text-base"><Warehouse className="h-4 w-4" /> Inventory Check</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-3 text-sm">
                           {inventoryStatus.crateStatus && (
                                <div>
                                    <div className="flex justify-between items-center">
                                        <span className="font-semibold">Crates</span>
                                        <Badge variant="outline" className={cn(inventoryStatusStyles[inventoryStatus.crateStatus.status])}>{inventoryStatus.crateStatus.status}</Badge>
                                    </div>
                                    <p className="text-muted-foreground text-xs">Required: {inventoryStatus.crateStatus.needed} | Available: {inventoryStatus.crateStatus.available}</p>
                                </div>
                            )}
                            {inventoryStatus.itemStatus.map((item, index) => (
                                 <div key={index}>
                                    <div className="flex justify-between items-center">
                                        <span className="font-semibold">{item.name}</span>
                                        <Badge variant="outline" className={cn(inventoryStatusStyles[item.status])}>{item.status}</Badge>
                                    </div>
                                    <p className="text-muted-foreground text-xs">Required: {item.needed} | Available: {item.available}</p>
                                </div>
                            ))}
                             {inventoryStatus.itemStatus.length === 0 && !inventoryStatus.crateStatus && (
                                <p className="text-muted-foreground text-center text-xs pt-4">No trackable items in this request.</p>
                             )}
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}

function ContactMessagesSection({ messages, setMessages }: { messages: ContactMessageWithId[], setMessages: React.Dispatch<React.SetStateAction<ContactMessageWithId[]>> }) {
    const { idToken } = useUser();
    const { toast } = useToast();

    const handleStatusChange = async (messageId: string, status: ContactMessageWithId['status']) => {
        if (!idToken) { toast({ variant: 'destructive', title: 'Authentication Error', description: 'Cannot update status.' }); return; }
        const result = await updateMessageStatus(idToken, { messageId, status });
        if (result.success) {
            setMessages(prev => prev.map(msg => msg.id === messageId ? { ...msg, status } : msg));
            toast({ title: "Status Updated", description: `Message marked as ${status}.` });
        } else { toast({ variant: 'destructive', title: 'Update Failed', description: result.error }); }
    };
    
    return (
        <Card>
            <CardHeader><CardTitle>Contact Messages</CardTitle><CardDescription>Manage inquiries from the contact form.</CardDescription></CardHeader>
            <CardContent>
                {messages && messages.length > 0 ? (
                     <Accordion type="single" collapsible className="w-full">
                        {messages.map((message) => (
                             <AccordionItem value={message.id} key={message.id}>
                                <AccordionTrigger className="hover:bg-muted/50 px-4 rounded-lg data-[state=open]:bg-muted/50" onClick={() => message.status === 'New' && handleStatusChange(message.id, 'Read')}>
                                    <div className="flex items-center gap-4 text-left flex-1">
                                        <div className="flex-grow"><p className="font-semibold">{message.name} <span className="text-sm text-muted-foreground font-normal">({message.email})</span></p><p className="text-sm text-muted-foreground">Submitted: {new Date(message.submittedDate).toLocaleString()}</p></div>
                                    </div>
                                    <div className="flex items-center gap-4 ml-auto pl-4">
                                         <Badge variant="outline" className={cn('whitespace-nowrap', messageStatusStyles[message.status])}>{message.status}</Badge>
                                        <DropdownMenu onOpenChange={(open) => { if(open) { event?.stopPropagation() }}}>
                                            <DropdownMenuTrigger asChild onClick={(e) => e.stopPropagation()}><Button aria-haspopup="true" size="icon" variant="ghost"><MoreHorizontal className="h-4 w-4" /><span className="sr-only">Toggle menu</span></Button></DropdownMenuTrigger>
                                            <DropdownMenuContent align="end">
                                            <DropdownMenuLabel>Actions</DropdownMenuLabel>
                                            <DropdownMenuItem onClick={() => handleStatusChange(message.id, 'Read')}><Eye className="mr-2 h-4 w-4" />Mark as Read</DropdownMenuItem>
                                            <DropdownMenuItem onClick={() => handleStatusChange(message.id, 'Archived')}><Archive className="mr-2 h-4 w-4" />Archive</DropdownMenuItem>
                                            </DropdownMenuContent>
                                        </DropdownMenu>
                                    </div>
                                </AccordionTrigger>
                                <AccordionContent><div className="p-4 bg-muted/20 dark:bg-muted/50 rounded-b-lg"><p className="whitespace-pre-wrap">{message.message}</p></div></AccordionContent>
                            </AccordionItem>
                        ))}
                    </Accordion>
                ) : ( <div className="text-center py-16 border rounded-lg bg-muted/20"><h3 className="text-xl font-semibold">No messages yet.</h3><p className="text-muted-foreground mt-2">New messages from your contact form will appear here.</p></div> )}
            </CardContent>
        </Card>
    );
}

function RequestsSection({ requests, setRequests, inventory }: { requests: QuoteRequestWithId[], setRequests: React.Dispatch<React.SetStateAction<QuoteRequestWithId[]>>, inventory: InventoryItem[] }) {
    const [filterStatus, setFilterStatus] = useState<QuoteRequestWithId['status'] | 'All'>('All');
    const [searchTerm, setSearchTerm] = useState('');
    const { idToken } = useUser();
    const { toast } = useToast();

    const filterStatuses: (QuoteRequestWithId['status'] | 'All')[] = ['All', 'Pending', 'In Review', 'Approved', 'Paid', 'Rejected', 'Completed'];

     const handleStatusChange = async (customerId: string, quoteId: string, status: QuoteRequestWithId['status']) => {
        if (!idToken) { toast({ variant: 'destructive', title: 'Authentication Error' }); return; }
        const result = await updateQuoteStatus(idToken, { customerId, quoteId, status });
        if (result.success) {
            setRequests(prevRequests => prevRequests.map(req => req.id === quoteId ? { ...req, status } : req));
            toast({ title: "Status Updated", description: `Quote ${quoteId} marked as ${status}.` });
        } else { toast({ variant: 'destructive', title: 'Update Failed', description: result.error }); }
    };
    
    const filteredRequests = useMemo(() => {
        return requests
            .filter(request => filterStatus === 'All' || request.status === filterStatus)
            .filter(request => {
                if (!searchTerm) return true;
                const lowerCaseSearch = searchTerm.toLowerCase();
                return (request.customerName?.toLowerCase() || '').includes(lowerCaseSearch) ||
                       (request.customerEmail?.toLowerCase() || '').includes(lowerCaseSearch) ||
                       request.id.toLowerCase().includes(lowerCaseSearch);
            });
    }, [requests, filterStatus, searchTerm]);
    
    return (
        <Card>
            <CardHeader><CardTitle>Incoming Requests</CardTitle><CardDescription>Review and manage all customer quote requests.</CardDescription></CardHeader>
            <CardContent>
                 <div className="flex flex-col sm:flex-row items-center gap-4 mb-6">
                    <div className="relative w-full sm:w-auto sm:flex-1"><Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" /><Input type="search" placeholder="Search by name, email, or ID..." className="w-full rounded-lg bg-background pl-8" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} /></div>
                    <div className="flex items-center gap-2 overflow-x-auto pb-2">{filterStatuses.map(status => (<Button key={status} variant={filterStatus === status ? 'default' : 'outline'} size="sm" onClick={() => setFilterStatus(status)} className="whitespace-nowrap">{status}</Button>))}</div>
                </div>

                {filteredRequests && filteredRequests.length > 0 ? (
                    <Accordion type="single" collapsible className="w-full">
                        {filteredRequests.map((request) => (
                            <AccordionItem value={request.id} key={request.id}>
                                <AccordionTrigger className="hover:bg-muted/50 px-4 rounded-lg data-[state=open]:bg-muted/50">
                                    <div className="flex items-center gap-4 text-left flex-1">
                                        <div className="flex-grow"><p className="font-semibold">{request.projectDescription || 'Quote Request'}</p><p className="text-sm text-muted-foreground">{request.customerName} - Submitted: {new Date(request.submittedDate).toLocaleDateString()}</p></div>
                                    </div>
                                    <div className="flex items-center gap-4 ml-auto pl-4">
                                        <Badge variant="outline" className={cn('whitespace-nowrap', quoteStatusStyles[request.status])}>{request.status}</Badge>
                                        <DropdownMenu onOpenChange={(open) => { if(open) { event?.stopPropagation() }}}>
                                            <DropdownMenuTrigger asChild onClick={(e) => e.stopPropagation()}><Button aria-haspopup="true" size="icon" variant="ghost"><MoreHorizontal className="h-4 w-4" /><span className="sr-only">Toggle menu</span></Button></DropdownMenuTrigger>
                                            <DropdownMenuContent align="end">
                                            <DropdownMenuLabel>Actions</DropdownMenuLabel>
                                            <DropdownMenuItem onClick={() => handleStatusChange(request.customerId, request.id, 'Approved')}><CheckCircle className="mr-2 h-4 w-4" />Approve</DropdownMenuItem>
                                            <DropdownMenuItem onClick={() => handleStatusChange(request.customerId, request.id, 'Rejected')}><XCircle className="mr-2 h-4 w-4" />Reject</DropdownMenuItem>
                                            <DropdownMenuItem onClick={() => handleStatusChange(request.customerId, request.id, 'In Review')}><Clock className="mr-2 h-4 w-4" />Mark as In Review</DropdownMenuItem>
                                            </DropdownMenuContent>
                                        </DropdownMenu>
                                    </div>
                                </AccordionTrigger>
                                <AccordionContent>
                                    <QuoteRequestDetails request={request} allRequests={requests} inventory={inventory} />
                                </AccordionContent>
                            </AccordionItem>
                        ))}
                    </Accordion>
                ) : ( <div className="text-center py-16 border rounded-lg bg-muted/20"><h3 className="text-xl font-semibold">No quote requests found.</h3><p className="text-muted-foreground mt-2">Try adjusting your search or filter.</p></div> )}
            </CardContent>
        </Card>
    );
}

function InventorySection({ initialInventory, onInventoryUpdate }: { initialInventory: InventoryItem[], onInventoryUpdate: (items: InventoryItem[]) => void }) {
    const [inventory, setInventory] = useState(initialInventory);
    const [isSaving, setIsSaving] = useState(false);
    const { idToken } = useUser();
    const { toast } = useToast();

    useEffect(() => {
        setInventory(initialInventory);
    }, [initialInventory]);
    
    const rentableItems = useMemo(() => {
        return [...otherServices, ...protectionAddOns, ...tvProtectionAddOns].filter(item => item.trackInventory);
    }, []);

    const handleQuantityChange = (id: string, name: string, change: number, type: 'crate_pool' | 'item') => {
        setInventory(prev => {
            const existingItemIndex = prev.findIndex(item => item.id === id);
            const newInventory = [...prev];
            if (existingItemIndex > -1) {
                const updatedItem = { ...newInventory[existingItemIndex] };
                updatedItem.quantity = Math.max(0, updatedItem.quantity + change);
                newInventory[existingItemIndex] = updatedItem;
            } else {
                newInventory.push({ id, name, quantity: Math.max(0, change), type });
            }
            return newInventory;
        });
    };
    
    const handleSave = async () => {
        if (!idToken) { toast({ variant: 'destructive', title: 'Authentication Error' }); return; }
        setIsSaving(true);
        try {
            await Promise.all(inventory.map(item => setInventoryItem(idToken, { itemId: item.id, data: item })));
            onInventoryUpdate(inventory);
            toast({ title: "Inventory Saved", description: "Your stock levels have been updated." });
        } catch (error: any) {
            toast({ variant: 'destructive', title: 'Save Failed', description: error.message });
        } finally {
            setIsSaving(false);
        }
    };
    
    const getQuantity = (id: string) => inventory.find(i => i.id === id)?.quantity || 0;

    return (
        <Card>
            <CardHeader>
                <CardTitle>Manage Inventory</CardTitle>
                <CardDescription>Set the total quantity you own for each rental item.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
                <div className="p-4 border rounded-lg">
                    <Label htmlFor="crates-quantity" className="text-lg font-semibold">Total Crates Owned</Label>
                    <p className="text-sm text-muted-foreground mb-2">Set the total number of individual moving boxes in your inventory.</p>
                    <div className="flex items-center gap-2 max-w-xs">
                        <Button type="button" variant="outline" size="icon" onClick={() => handleQuantityChange('crates', 'Crate Pool', -10, 'crate_pool')}><Minus className="h-4 w-4" /></Button>
                        <Input id="crates-quantity" type="number" value={getQuantity('crates')} onChange={e => handleQuantityChange('crates', 'Crate Pool', parseInt(e.target.value) - getQuantity('crates'), 'crate_pool')} className="text-center" />
                        <Button type="button" variant="outline" size="icon" onClick={() => handleQuantityChange('crates', 'Crate Pool', 10, 'crate_pool')}><Plus className="h-4 w-4" /></Button>
                    </div>
                </div>
                 <div className="space-y-4">
                    <Label className="text-lg font-semibold">Other Rental Items</Label>
                    <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
                        {rentableItems.map(item => (
                            <div key={item.id} className="p-3 border rounded-lg space-y-2">
                                <div>
                                    <p className="font-medium leading-tight">{item.name}</p>
                                    {item.name.includes('Moving Blanket') && item.description && <p className="text-xs text-muted-foreground">{item.description}</p>}
                                </div>
                                <div className="flex items-center justify-between pt-1">
                                    <Label htmlFor={`item-${item.id}`} className="text-sm text-muted-foreground">Quantity</Label>
                                    <div className="flex items-center gap-2">
                                        <Button type="button" variant="outline" size="icon" className="h-6 w-6" onClick={() => handleQuantityChange(item.id, item.name, -1, 'item')}><Minus className="h-3 w-3" /></Button>
                                        <Input id={`item-${item.id}`} type="number" value={getQuantity(item.id)} onChange={e => handleQuantityChange(item.id, item.name, parseInt(e.target.value) - getQuantity(item.id), 'item')} className="h-8 w-12 text-center" />
                                        <Button type="button" variant="outline" size="icon" className="h-6 w-6" onClick={() => handleQuantityChange(item.id, item.name, 1, 'item')}><Plus className="h-3 w-3" /></Button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
                <Button onClick={handleSave} disabled={isSaving}>
                    {isSaving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                    Save Inventory
                </Button>
            </CardContent>
        </Card>
    );
}

// --- MAIN PAGE COMPONENT ---
function AdminDashboard() {
    const [requests, setRequests] = useState<QuoteRequestWithId[]>([]);
    const [messages, setMessages] = useState<ContactMessageWithId[]>([]);
    const [inventory, setInventory] = useState<InventoryItem[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const { idToken } = useUser();

    const pendingRequestsCount = useMemo(() => requests.filter(r => r.status === 'Pending' || r.status === 'In Review').length, [requests]);
    const newMessagesCount = useMemo(() => messages.filter(m => m.status === 'New').length, [messages]);


    const fetchData = useCallback(async (token: string) => {
        setIsLoading(true);
        const [reqResult, msgResult, invResult] = await Promise.all([
            getAdminQuoteRequests(token),
            getContactMessages(token),
            getInventory(token)
        ]);
        let fetchError = '';

        if (reqResult.success) {
            const parsedRequests = reqResult.data.map(req => ({ ...req, submittedDate: req.submittedDate || new Date().toISOString() }));
            parsedRequests.sort((a, b) => new Date(b.submittedDate).getTime() - new Date(a.submittedDate).getTime());
            setRequests(parsedRequests);
        } else { fetchError += `Failed to load quotes: ${reqResult.error}\n`; }

        if (msgResult.success) {
            setMessages(msgResult.data);
        } else { fetchError += `Failed to load messages: ${msgResult.error}\n`; }

        if (invResult.success) {
            setInventory(invResult.data);
        } else { fetchError += `Failed to load inventory: ${invResult.error}\n`; }

        if(fetchError) setError(fetchError);
        setIsLoading(false);
    }, []);

    useEffect(() => {
        if (!idToken) { setIsLoading(false); setError("Could not get authentication token."); return; }
        fetchData(idToken);
    }, [idToken, fetchData]);

    if (error) {
        return ( <Card className="max-w-xl mx-auto bg-destructive/10 border-destructive"><CardHeader><CardTitle className="text-destructive flex items-center gap-2"><AlertTriangle /> Error Fetching Data</CardTitle><CardDescription className="text-destructive/90">Could not fetch data.</CardDescription></CardHeader><CardContent><p className="font-semibold">Error Details:</p><pre className="mt-2 w-full whitespace-pre-wrap rounded-md bg-destructive/10 p-4 text-xs font-mono text-destructive-foreground">{error}</pre></CardContent></Card> );
    }

    if (isLoading) {
        return ( <div className="flex justify-center items-center h-48"><Loader2 className="h-8 w-8 animate-spin text-primary" /><p className="ml-4 text-muted-foreground">Loading dashboard...</p></div> );
    }
    
    return (
        <Tabs defaultValue="overview" className="space-y-4">
          <TabsList className="grid w-full grid-cols-5">
            <TabsTrigger value="overview"><GanttChartSquare className="mr-2 h-4 w-4" />Overview</TabsTrigger>
            <TabsTrigger value="requests">
                <ClipboardList className="mr-2 h-4 w-4" />
                Requests 
                {pendingRequestsCount > 0 && <Badge variant="secondary" className="ml-2">{pendingRequestsCount}</Badge>}
            </TabsTrigger>
            <TabsTrigger value="schedule"><CalendarIcon className="mr-2 h-4 w-4" />Schedule</TabsTrigger>
            <TabsTrigger value="messages">
                <MessageSquare className="mr-2 h-4 w-4" />
                Messages 
                {newMessagesCount > 0 && <Badge variant="secondary" className="ml-2">{newMessagesCount}</Badge>}
            </TabsTrigger>
            <TabsTrigger value="inventory"><Warehouse className="mr-2 h-4 w-4" />Inventory</TabsTrigger>
          </TabsList>
          
          <TabsContent value="overview" className="space-y-4">
            <AnalyticsSection requests={requests} messages={messages} />
            <LiveRentalsSection requests={requests} />
          </TabsContent>

          <TabsContent value="requests" className="space-y-4">
            <RequestsSection requests={requests} setRequests={setRequests} inventory={inventory} />
          </TabsContent>
          
          <TabsContent value="schedule" className="space-y-4">
            <RentalCalendar requests={requests} />
          </TabsContent>

          <TabsContent value="messages">
            <ContactMessagesSection messages={messages} setMessages={setMessages} />
          </TabsContent>

          <TabsContent value="inventory">
            <InventorySection initialInventory={inventory} onInventoryUpdate={(updated) => { setInventory(updated); if(idToken) fetchData(idToken); }} />
          </TabsContent>
        </Tabs>
    );
}

export default function AdminDashboardPage() {
  const { isAdmin, isCheckingAdmin } = useAdmin();

  if (isCheckingAdmin) {
    return ( <div className="flex justify-center items-center h-48"><Loader2 className="h-8 w-8 animate-spin text-primary" /><p className="ml-4 text-muted-foreground">Verifying admin access...</p></div> );
  }

  return (
    <div className="container mx-auto py-8">
      <header className="mb-8"><h1 className="text-4xl font-bold text-foreground">Admin Dashboard</h1><p className="mt-2 text-lg text-muted-foreground">Your central command center for managing requests, messages, and inventory.</p></header>
       {isAdmin ? <AdminDashboard /> : (
        <Card className="max-w-lg mx-auto"><CardHeader className="text-center"><CardTitle>Access Denied</CardTitle><CardDescription>You do not have permission to view this page.</CardDescription></CardHeader></Card>
        )}
    </div>
  );
}
